export const THEME_SUMMARIES = {
  // ── CLÍNICA MÉDICA ──
  "has e sd. metabólica": { area: "clinica", resumo: "HAS: metas PA <140/90 (geral), <130/80 (alto risco). Diagnóstico: ≥140/90 em 2 consultas ou MAPA/MRPA. Drogas 1ª linha: IECA/BRA, BCC, tiazídico. Sd. Metabólica (IDF): obesidade central + 2 de: TG≥150, HDL baixo, PA≥130/85, glicemia≥100.", topicos: [{t:"Classificação e metas pressóricas (VII Diretriz Brasileira de HAS)", d:"Normal <120/80; Elevada 120-129/<80; Estágio 1 ≥130/80; Estágio 2 ≥140/90. Meta geral <140/90, alto risco <130/80."}, {t:"Lesão de órgão-alvo (microalbuminúria, HVE, retinopatia)", d:"Avaliar: microalbuminúria >30mg/g, HVE no ECG (Sokolow-Lyon), retinopatia hipertensiva graus I-IV (Keith-Wagener)."}, {t:"Crise hipertensiva: urgência vs emergência", d:"Emergência: PA elevada + LOA aguda (EAP, AVE, dissecção) → nitroprussiato IV. Urgência: sem LOA → captopril VO, reduzir em 24-48h."}, {t:"Critérios IDF/NCEP para Sd. Metabólica", d:"IDF: obesidade central obrigatória + 2 de: TG≥150, HDL baixo (H<40/M<50), PA≥130/85, GJ≥100. NCEP: 3 de 5 critérios."}, {t:"Tratamento não-farmacológico (DASH, atividade física)", d:"Dieta DASH reduz ~11mmHg na PAS. Atividade aeróbica 150min/sem. Restrição de sódio <2g/dia."}] },
  "pneumonia/sepse (anemia falciforme)": { area: "clinica", resumo: "Pneumonia: agente mais comum comunidade = S. pneumoniae. CURB-65 define internação. Sepse (Sepsis-3): infecção + SOFA≥2. Choque séptico: vasopressor para PAM≥65 + lactato>2. Na falciforme: germes encapsulados (pneumococo) por asplenia funcional; Sd. Torácica Aguda = febre + infiltrado + sintoma respiratório.", topicos: [{t:"CURB-65 e PORT/PSI para estratificação", d:"CURB-65: Confusão, Ureia>50, FR≥30, PA<90/60, ≥65a. 0-1=ambulatorial, 2=considerar internação, ≥3=UTI."}, {t:"Antibioticoterapia empírica (BTS/IDSA)", d:"Ambulatorial: amoxicilina ou macrolídeo. Enfermaria: amox-clav + macrolídeo ou quinolona respiratória. UTI: beta-lactâmico + macrolídeo."}, {t:"Critérios qSOFA e SOFA (Sepsis-3)", d:"qSOFA (triagem): FR≥22, PAS≤100, Glasgow<15 (≥2 = suspeitar sepse). SOFA≥2 confirma disfunção orgânica."}, {t:"Sd. Torácica Aguda na falciforme", d:"Infiltrado pulmonar novo + febre/tosse/dor torácica/hipóxia em falcêmico. Tratar com ATB, transfusão e suporte."}, {t:"Bundle da hora (Surviving Sepsis Campaign)", d:"Na 1ª hora: lactato, hemocultura, ATB de amplo espectro, cristaloide 30mL/kg se hipotensão, vasopressor se PAM<65 após volume."}] },
  "sd. ictérica": { area: "clinica", resumo: "Icterícia: BD↑ = colestase (obstrução ou hepatocelular). BI↑ = hemólise ou Gilbert. Hepatites virais: A (fecal-oral, IgM anti-HAV), B (HBsAg, anti-HBc), C (anti-HCV, RNA). Coledocolitíase: icterícia flutuante + dor biliar + ↑FA/GGT. Colangite aguda (Charcot: febre+icterícia+dor; Reynolds: +hipotensão+confusão).", topicos: [{t:"Diferencial de icterícia às custas de BD vs BI", d:"BD↑: colestase (obstrutiva ou hepatocelular). BI↑: hemólise, Gilbert, Crigler-Najjar. Relação BD/BT>50% sugere colestase."}, {t:"Marcadores sorológicos das hepatites (janela imunológica)", d:"HBV: HBsAg (infecção), anti-HBc IgM (aguda), anti-HBs (cura/vacina). Janela: HBsAg- e anti-HBs- com anti-HBc IgM+."}, {t:"Síndrome colestática: USG → ColangioRM → CPRE", d:"USG 1º passo: vias biliares dilatadas? ColangioRM define nível. CPRE é terapêutica (papilotomia + extração de cálculo)."}, {t:"Tríade de Charcot e pêntade de Reynolds", d:"Charcot: febre + icterícia + dor em HCD (colangite). Reynolds: Charcot + hipotensão + confusão mental (colangite supurativa grave)."}, {t:"Hepatite autoimune vs CBP vs CEP", d:"HAI: FAN/anti-músculo liso, ↑transaminases. CBP: anti-mitocôndria, ↑FA, mulheres. CEP: p-ANCA, colangioRM com estenoses, associada a RCU."}] },
  "sd. ictérica i (sem. 01)": { area: "clinica", resumo: "Hepatites virais: HAV (IgM aguda, IgG imunidade), HBV (HBsAg>6m=crônica, HBeAg=replicação, anti-HBs=cura/vacina), HCV (anti-HCV+RNA confirma). Hepatite B crônica: tratar se HBeAg+ com ALT>2x ou fibrose. Hepatite C: tratar todos (DAAs: sofosbuvir+daclatasvir). Profilaxia HBV: vacina 3 doses + HBIG se exposição.", topicos: [{t:"Interpretação de painel sorológico HBV completo", d:"HBsAg+/anti-HBc+/anti-HBs-=infecção. HBeAg+=replicação viral ativa. Anti-HBe+=soroconversão. Anti-HBs isolado=vacina."}, {t:"Indicações de tratamento HBV crônica (PCDT/MS)", d:"Tratar se: HBeAg+ com ALT>2x LSN, fibrose significativa (≥F2), coinfecção HIV ou HCV, manifestações extra-hepáticas."}, {t:"Esquema DAA para HCV (PCDT MS 2019)", d:"Sofosbuvir + daclatasvir ± ribavirina por 12-24 semanas. Tratar TODOS os pacientes com HCV crônica. Cura (RVS) >95%."}, {t:"Profilaxia pós-exposição (HBIG + vacina)", d:"HBIG até 72h + iniciar esquema vacinal. Indicações: RN de mãe HBsAg+, acidente perfurocortante com fonte HBsAg+."}, {t:"Hepatite A fulminante e indicação de transplante", d:"Hepatite A fulminante é rara (<1%), mas grave. Critérios de King's College para indicação de transplante hepático de urgência."}] },
  "sd. ictérica ii (sem. 02)": { area: "clinica", resumo: "Icterícia obstrutiva: USG mostra dilatação de vias biliares → ColangioRM → CPRE terapêutica. Coledocolitíase: cálculo no colédoco, ↑BD, FA, GGT. Tumores periampulares: icterícia progressiva + vesícula palpável (sinal de Courvoisier). Colangiocarcinoma: estenose biliar + CA 19-9. CEP: colangite esclerosante primária associada a RCU.", topicos: [{t:"Algoritmo diagnóstico da icterícia obstrutiva", d:"USG (dilatação de vias biliares?) → ColangioRM (nível da obstrução) → CPRE terapêutica ou cirurgia conforme etiologia."}, {t:"Sinal de Courvoisier-Terrier", d:"Vesícula palpável e indolor + icterícia = obstrução distal neoplásica (cabeça de pâncreas). Não ocorre na coledocolitíase (vesícula fibrosada)."}, {t:"Tumor de Klatskin (classificação Bismuth)", d:"Colangiocarcinoma peri-hilar. Bismuth I: abaixo da confluência; II: na confluência; IIIa/b: hepático D ou E; IV: bilateral."}, {t:"Indicações de CPRE vs cirurgia", d:"CPRE: coledocolitíase, estenoses benignas, drenagem paliativa. Cirurgia: tumores ressecáveis, falha de CPRE, perfuração."}, {t:"Diferencial de estenoses biliares benignas vs malignas", d:"Benignas: pós-cirúrgica, CEP, pancreatite crônica. Malignas: colangiocarcinoma, Ca de pâncreas, Ca de vesícula. Escovado biliar para citologia."}] },
  "sd. diarreica": { area: "clinica", resumo: "Diarreia aguda (<14d): maioria viral (rotavírus, norovírus). Bacteriana: febre + sangue → Salmonella, Shigella, Campylobacter. C. difficile: pós-ATB, toxina A/B, tratar com vancomicina VO. Diarreia crônica: osmótica (gap osmolar alto), secretória (gap baixo), inflamatória (sangue/muco). Doença celíaca: anti-tTG IgA + biópsia duodenal.", topicos: [{t:"Classificação osmótica vs secretória vs inflamatória", d:"Osmótica: gap osmolar fecal >125, melhora com jejum. Secretória: gap <50, persiste com jejum. Inflamatória: sangue/muco, leucócitos fecais."}, {t:"C. difficile: diagnóstico e tratamento (IDSA)", d:"Toxina A/B por ELISA ou PCR. Leve-moderada: vancomicina 125mg VO 6/6h 10d. Grave: vancomicina VO + metronidazol IV. Fidaxomicina se recorrente."}, {t:"Doença celíaca: anti-tTG IgA e classificação Marsh", d:"Anti-tTG IgA é o melhor teste de triagem. Biópsia duodenal: Marsh 0 (normal) a 3c (atrofia total de vilosidades). Dieta sem glúten é o tratamento."}, {t:"DII: Crohn vs RCU (tabela comparativa)", d:"Crohn: transmural, qualquer segmento (íleo terminal), granulomas, fístulas. RCU: mucosa/submucosa, reto→cólon, contínua, pseudopólipos."}, {t:"Síndrome do intestino irritável (critérios Roma IV)", d:"Dor abdominal recorrente ≥1x/sem nos últimos 3 meses, associada a evacuação, mudança de frequência ou forma das fezes."}] },
  "diabetes/cad": { area: "clinica", resumo: "DM2: diagnóstico com GJ≥126, HbA1c≥6.5%, TOTG≥200. Meta HbA1c <7%. CAD: glicemia>250 + pH<7.3 + cetonemia. Tratamento CAD: SF 0.9% 1-1.5L/h → insulina regular 0.1U/kg/h → repor K+ se <5.2 antes da insulina. Estado hiperosmolar: glicemia>600, osmolaridade>320, sem cetose significativa.", topicos: [{t:"Critérios diagnósticos DM (SBD/ADA)", d:"GJ≥126, TOTG 2h≥200, HbA1c≥6.5% ou glicemia aleatória≥200 com sintomas. Dois exames alterados confirmam."}, {t:"Algoritmo de tratamento DM2 (metformina → iSGLT2/aGLP1)", d:"Metformina 1ª linha. Associar iSGLT2 (benefício renal/cardíaco) ou aGLP-1 (perda peso/CV). HbA1c>10% ou sintomático: iniciar insulina."}, {t:"Protocolo CAD: hidratação → K+ → insulina", d:"SF 0.9% 1-1.5L/h na 1ª hora. Se K+<5.2, repor antes da insulina. Insulina regular 0.1U/kg/h IV. Resolver quando pH>7.3, BIC>15, AG<12."}, {t:"Diferença CAD vs EHH", d:"CAD: glicemia>250, pH<7.3, cetonemia, AG elevado. EHH: glicemia>600, osm>320, sem cetose significativa, mortalidade maior."}, {t:"Metas glicêmicas individualizadas (ADA 2024)", d:"HbA1c<7% para maioria. Idosos frágeis <8%. Jovens sem complicações considerar <6.5%. GJ 80-130, pós-prandial <180."}] },
  "miastenia gravis": { area: "clinica", resumo: "Autoimune: anti-AChR (85%) ou anti-MuSK. Fraqueza flutuante pior ao esforço, melhora com repouso. Ptose + diplopia = forma ocular. Diagnóstico: anti-AChR + ENMG (decremento >10%). Tratamento: piridostigmina (sintomático) + imunossupressão (prednisona, azatioprina). Crise miastênica: fraqueza respiratória → UTI + plasmaférese ou IVIg. TC tórax: buscar timoma.", topicos: [{t:"Diferença crise miastênica vs crise colinérgica", d:"Miastênica: fraqueza por piora da doença, pupilas normais, melhora com anticolinesterásico. Colinérgica: excesso de piridostigmina, miose, sialorreia, piora com anticolinesterásico."}, {t:"Indicação de timectomia (timoma ou <65a com anti-AChR+)", d:"Timoma: indicação absoluta. Sem timoma: anti-AChR+ entre 18-65 anos com MG generalizada, benefício a longo prazo (estudo MGTX)."}, {t:"Drogas que pioram miastenia (aminoglicosídeos, betabloqueadores)", d:"Evitar: aminoglicosídeos, quinolonas, betabloqueadores, magnésio IV, D-penicilamina, bloqueadores neuromusculares despolarizantes."}, {t:"Anti-MuSK: forma bulbar, sem timoma", d:"Predomínio bulbar (disfagia, disartria), atrofia facial/lingual. Pior resposta à piridostigmina. Timectomia geralmente não indicada."}, {t:"ENMG com estimulação repetitiva", d:"Decremento >10% na estimulação repetitiva a 3Hz confirma defeito na junção neuromuscular. Fibra única (jitter) é o teste mais sensível."}] },
  "sífilis reinfecção": { area: "clinica", resumo: "Reinfecção: elevação ≥2 diluições no VDRL (ex: 1:4→1:16) após tratamento adequado. Sífilis primária: cancro duro (indolor). Secundária: roséolas, condiloma plano, alopecia. Latente: assintomática (recente <1a, tardia >1a). Terciária: goma, tabes dorsalis, aneurisma aórtico. Tratamento: penicilina benzatina (primária 2.4MUI dose única; tardia 3 doses semanais).", topicos: [{t:"Critérios de reinfecção vs falha terapêutica (MS)", d:"Reinfecção: elevação ≥2 diluições (4x o título) após tratamento adequado. Falha: queda <2 diluições em 6 meses (recente) ou 12 meses (tardia)."}, {t:"Interpretação VDRL quantitativo no seguimento", d:"Controle trimestral. Queda esperada: ≥2 diluições em 6m (recente), 12m (tardia). Cicatriz sorológica: VDRL baixo e estável após tratamento."}, {t:"Neurossífilis: quando puncionar (VDRL>1:32, HIV+, sintomas neurológicos)", d:"Indicações de punção lombar: sinais neurológicos/oftalmológicos, VDRL>1:32, HIV+, falha terapêutica. LCR: VDRL+ (específico), pleocitose, proteinorraquia."}, {t:"Esquemas de penicilina por estágio", d:"Primária/secundária/latente recente: PB 2.4MUI IM dose única. Latente tardia/terciária: PB 2.4MUI IM semanal × 3. Neuro: P. cristalina 4MUI IV 4/4h × 14d."}, {t:"Reação de Jarisch-Herxheimer", d:"Febre, cefaleia, mialgia 12-24h após 1ª dose de penicilina. Autolimitada. Mais comum na secundária. Não suspender tratamento, manejar com sintomáticos."}] },
  "sd. metabólica ii — diabetes": { area: "clinica", resumo: "DM2: GJ≥126, TOTG≥200, HbA1c≥6.5%. Pré-DM: GJ 100-125. Meta HbA1c<7%. 1ª linha: metformina. Benefício CV: iSGLT2 (empagliflozina) e aGLP-1 (liraglutida). DM1: insulinoterapia basal-bolus. CAD: insulina + hidratação + K+.", topicos: [{t:"Rastreamento DM2 (ADA: ≥35a ou IMC≥25 + fator de risco)", d:"ADA: rastrear ≥35a ou qualquer idade com IMC≥25 + fator de risco (HAS, dislipidemia, SOP, história familiar, etnia). Repetir a cada 3 anos."}, {t:"Algoritmo SBD/ADA de tratamento escalonado", d:"1ª linha: metformina. HbA1c>7%: adicionar 2º agente. DCV: iSGLT2 ou aGLP-1. HbA1c>9%: considerar insulina ou terapia dupla inicial."}, {t:"Indicações de iSGLT2 e aGLP-1 (benefício renal/CV)", d:"iSGLT2: reduz IC e progressão DRC (TFG 20-45: dapagliflozina). aGLP-1: reduz MACE e peso. Ambos recomendados independente da HbA1c se DCV ou DRC."}, {t:"Manejo de CAD e EHH", d:"CAD: volume + K+ (se<5.2) + insulina regular IV. EHH: hidratação vigorosa é prioridade. Ambos: monitorar K+, glicemia e AG a cada 2-4h."}, {t:"Insulinização no DM2: quando e como iniciar", d:"Indicar se: HbA1c>9% sintomático, falha de 2-3 agentes orais, gravidez. Iniciar com basal (NPH noturna ou glargina) 10UI, titular a cada 3 dias."}] },
  "sd. endócrinas — tireoide": { area: "clinica", resumo: "Hipotireoidismo: TSH↑, T4L↓. Hashimoto: anti-TPO+. Tratar com levotiroxina. Hipertireoidismo: TSH↓, T4L↑. Graves: TRAb+, bócio difuso, oftalmopatia. Nódulo tireoidiano: TSH + USG → PAAF se TI-RADS ≥4 ou ≥1cm suspeito. Bethesda I-VI guia conduta.", topicos: [{t:"Interpretação TSH + T4L (hipo subclínico: TSH↑, T4L normal)", d:"Hipo subclínico: TSH 4.5-10 com T4L normal. Tratar se: TSH>10, anti-TPO+, sintomas, gestante ou desejo de gestar."}, {t:"Diagnóstico diferencial de tireotoxicose (Graves vs nódulo tóxico)", d:"Graves: TRAb+, bócio difuso, oftalmopatia, captação difusa na cintilografia. Nódulo tóxico: nódulo hipercaptante com supressão do restante."}, {t:"Classificação TI-RADS e indicação de PAAF", d:"TI-RADS 1-2: sem PAAF. TI-RADS 3: PAAF se ≥2.5cm. TI-RADS 4: PAAF se ≥1.5cm. TI-RADS 5: PAAF se ≥1cm. ACR TI-RADS pontua composição, ecogenicidade, forma, margem, focos."}, {t:"Sistema Bethesda e conduta por categoria", d:"I: repetir PAAF. II: seguimento. III: repetir ou teste molecular. IV: lobectomia. V: lobectomia ou tireoidectomia. VI: tireoidectomia total."}, {t:"Crise tireotóxica: PTU + iodo + betabloqueador + corticoide", d:"Escala de Burch-Wartofsky ≥45. PTU (bloqueia síntese + conversão periférica) → iodo 1h após (bloqueia liberação). Propranolol + dexametasona. Suporte em UTI."}] },
  // ── CIRURGIA ──
  "empiema pleural": { area: "cirurgia", resumo: "Empiema: pus no espaço pleural, geralmente pós-pneumonia. Fases: exsudativa → fibrinopurulenta → organização. Diagnóstico: toracocentese com pH<7.2, glicose<40, LDH>1000, bacterioscopia/cultura+. Fase I-II: drenagem torácica em selo d'água. Fase III (encarceramento): decorticação (VATS ou aberta).", topicos: [{t:"Critérios de Light para exsudato vs transudato", d:"Exsudato se qualquer um: proteína LP/soro >0.5, LDH LP/soro >0.6, LDH LP >2/3 do limite sérico. Transudato: IC, cirrose, nefrose."}, {t:"Indicações de drenagem (pH<7.2, glicose<40, pus, loculação)", d:"Derrame parapneumônico complicado: pH<7.2, glicose<40, LDH>1000, Gram/cultura+, pus ou loculação. Drenar imediatamente."}, {t:"Fases do empiema e conduta em cada fase", d:"Fase I (exsudativa): ATB ± toracocentese. Fase II (fibrinopurulenta): drenagem + ATB. Fase III (organização/encarceramento): decorticação cirúrgica."}, {t:"Drenagem pleural: técnica e posicionamento", d:"5º EIC, entre axilar anterior e média, borda superior da costela inferior. Dissecção romba, exploração digital, dreno multifenestrado em selo d'água."}, {t:"Indicação de decorticação por VATS", d:"Fase III com encarceramento pulmonar (pulmão não expande após drenagem). VATS preferível se <2 semanas de evolução. Toracotomia se VATS falhar."}] },
  "drenagem pleural incorreta": { area: "cirurgia", resumo: "Drenagem torácica: inserção no 5º EIC, entre linhas axilar anterior e média, borda superior da costela inferior (evitar feixe vasculonervoso). Complicações: lesão de intercostal, diafragma, fígado/baço. Posição incorreta = ineficácia + risco de complicação.", topicos: [{t:"Triângulo de segurança para drenagem torácica", d:"Delimitado por: borda anterior do grande dorsal, borda lateral do peitoral maior e linha axilar do 5º EIC. Zona segura para inserção."}, {t:"Técnica de inserção (dissecção romba, dedo explorador)", d:"Incisão 2-3cm, dissecção romba com Kelly, perfuração da pleura, exploração digital para confirmar espaço livre, inserção do dreno."}, {t:"Complicações da drenagem mal posicionada", d:"Inserção baixa: lesão de diafragma, fígado (D) ou baço (E). Inserção medial: lesão de intercostal. Intraparenquimatosa: hemorragia e fístula aérea."}, {t:"Indicações: pneumotórax hipertensivo, hemotórax, empiema", d:"Pneumotórax hipertensivo: descompressão imediata (punção no 2º EIC → drenagem). Hemotórax: se >1500mL inicial ou >200mL/h, indicar toracotomia."}, {t:"Cuidados com sistema de selo d'água", d:"Frasco 2cm abaixo do nível d'água, manter abaixo do tórax. Oscilação = funcionante. Borbulhamento contínuo = fístula aérea. Nunca clampar durante transporte."}] },
  "dose máxima lidocaína": { area: "cirurgia", resumo: "Lidocaína sem vasoconstritor: 4.5 mg/kg. Com adrenalina: 7 mg/kg. Dose máxima absoluta: ~300mg (sem) / ~500mg (com). Intoxicação: parestesia perioral, zumbido, convulsão, arritmia. Tratamento: Intralipid 20% (emulsão lipídica IV).", topicos: [{t:"Doses máximas dos anestésicos locais (bupivacaína: 2mg/kg)", d:"Lidocaína: 4.5mg/kg (sem) e 7mg/kg (com vaso). Bupivacaína: 2mg/kg (sem) e 3mg/kg (com). Bupivacaína é a mais cardiotóxica."}, {t:"Sinais de intoxicação sistêmica (LAST)", d:"Sequência: parestesia perioral, gosto metálico, zumbido → convulsão → depressão do SNC → colapso cardiovascular. Bupivacaína causa arritmia refratária."}, {t:"Protocolo de Intralipid para LAST", d:"Emulsão lipídica 20%: bolus 1.5mL/kg IV seguido de infusão 0.25mL/kg/min. Repetir bolus se instabilidade persiste. É o antídoto específico."}, {t:"Efeito da adrenalina na duração e dose máxima", d:"Adrenalina 1:200.000 causa vasoconstrição local, reduz absorção, aumenta duração e permite maior dose máxima. Contraindicada em extremidades (dedos, pênis)."}, {t:"Bloqueios regionais: indicações e contraindicações", d:"Indicações: analgesia cirúrgica/pós-operatória, evitar AG. Contraindicações: coagulopatia, infecção no local, recusa do paciente, alergia ao anestésico."}] },
  "choque neurogênico": { area: "cirurgia", resumo: "Lesão medular acima de T6: perda do tônus simpático → vasodilatação + bradicardia. Diferente de choque hipovolêmico (taquicardia). Tríade: hipotensão + bradicardia + pele quente. Tratamento: volume + vasopressor (noradrenalina). Avaliar ATLS: sempre excluir hemorrágico primeiro.", topicos: [{t:"Diferencial de choque neurogênico vs medular vs hipovolêmico", d:"Neurogênico: hipotensão + bradicardia + pele quente (perda do simpático). Hipovolêmico: taquicardia + pele fria. Medular: arreflexia transitória pós-lesão, não é tipo de choque."}, {t:"Manejo inicial no trauma (ATLS: ABCDE)", d:"A: via aérea com proteção cervical. B: ventilação. C: circulação e controle de hemorragia. D: disfunção neurológica (Glasgow). E: exposição. Sempre excluir hemorrágico primeiro."}, {t:"Vasopressores de escolha (noradrenalina)", d:"Noradrenalina: 1ª escolha no choque neurogênico (efeito alfa vasoconstritor + beta1 cronotrópico). Dopamina como alternativa se bradicardia refratária."}, {t:"Nível da lesão e manifestações autonômicas", d:"Acima de T6: choque neurogênico com bradicardia severa. T6-L1: hipotensão sem bradicardia. Disreflexia autonômica: complicação crônica de lesão acima de T6."}, {t:"Choque medular: arreflexia transitória vs lesão definitiva", d:"Choque medular: arreflexia e flacidez abaixo da lesão nas primeiras 24-48h. Fim do choque = retorno do reflexo bulbocavernoso. Após isso, déficits residuais são definitivos."}] },
  "sd. dispéptica e doenças do tgi superior (sem. 05)": { area: "cirurgia", resumo: "Dispepsia: investigar H. pylori (teste respiratório ou Ag fecal). Úlcera péptica: gástrica (biopsiar sempre) vs duodenal (não precisa biopsiar). H. pylori+: erradicar (IBP+amoxicilina+claritromicina 14d). Complicações: HDA, perfuração, estenose. Ca gástrico: sinais de alarme (perda peso, disfagia, massa).", topicos: [{t:"Indicações de EDA (sinais de alarme, >40a)", d:"Sinais de alarme: perda de peso, disfagia, vômitos recorrentes, sangramento, anemia, massa palpável. EDA imediata se >40a com dispepsia nova."}, {t:"Esquema de erradicação do H. pylori (Maastricht/IV CBHP)", d:"1ª linha: IBP + amoxicilina 1g + claritromicina 500mg, 12/12h, 14 dias. Alergia à penicilina: IBP + claritromicina + metronidazol."}, {t:"Úlcera gástrica vs duodenal: fisiopatologia e conduta", d:"Gástrica: falha na defesa mucosa, biopsiar SEMPRE (excluir Ca). Duodenal: hipersecreção ácida, não precisa biopsiar, associação >90% com H. pylori."}, {t:"Classificação de Forrest para sangramento", d:"Ia: jato arterial. Ib: babação. IIa: vaso visível. IIb: coágulo aderido. IIc: hematina. III: base limpa. Ia-IIb: tratamento endoscópico + IBP IV."}, {t:"Indicações cirúrgicas na úlcera péptica", d:"Intratabilidade clínica, hemorragia refratária à endoscopia, perfuração (rafia + Graham) e obstrução pilórica (vagotomia + antrectomia ou piloroplastia)."}] },
  "hemorragia digestiva i (sem. 06)": { area: "cirurgia", resumo: "HDA: acima de Treitz. Causas: úlcera péptica (mais comum), varizes esofágicas, Mallory-Weiss. Estabilizar (ABCDE), IBP EV em bolus, EDA em até 24h. Varizes: terlipressina + ATB profilático + EDA com ligadura. Escores: Glasgow-Blatchford (necessidade de intervenção), Rockall (mortalidade).", topicos: [{t:"Manejo inicial da HDA (ressuscitação volêmica, hemoderivados)", d:"Estabilização hemodinâmica: 2 acessos calibrosos, cristaloide. Transfundir se Hb<7 (ou <9 se cardiopata). IBP 80mg bolus + 8mg/h IV. SNG controversa."}, {t:"Timing da EDA (urgente vs precoce)", d:"EDA em até 24h para todos. Urgente (<12h) se: instabilidade hemodinâmica, hematêmese ativa, suspeita de varizes. Glasgow-Blatchford=0 pode ter alta sem EDA."}, {t:"Tratamento endoscópico: clip, injeção, termocoagulação", d:"Forrest Ia-IIb: hemostasia endoscópica. Terapia combinada (adrenalina + método térmico ou mecânico) é superior à monoterapia."}, {t:"Varizes esofágicas: ligadura elástica + terlipressina (Baveno VII)", d:"Terlipressina 2mg IV 4/4h + ligadura elástica na EDA. ATB profilático (ceftriaxone 1g/dia) reduz mortalidade. Se refratário: TIPS ou balão de Sengstaken."}, {t:"Indicação de cirurgia na HDA refratária", d:"Falha de 2 tentativas endoscópicas ou instabilidade com >6CH transfundidos. Úlcera duodenal: pilorotomia + sutura do vaso. Úlcera gástrica: gastrectomia parcial."}] },
  "hemorragia digestiva ii — proctologia (sem. 08)": { area: "cirurgia", resumo: "HDB: abaixo de Treitz. Causas: doença diverticular (mais comum >60a), angiodisplasia, neoplasia. Geralmente autolimitada. Investigar: colonoscopia (após preparo). Se instável: angioTC → arteriografia. Proctologia: hemorroidas (graus I-IV), fissura anal (posterior, hipertonia), abscesso/fístula perianal.", topicos: [{t:"Investigação da HDB: colonoscopia vs angioTC vs cintilografia", d:"Colonoscopia: exame de escolha após estabilização (após preparo). AngioTC: sangramento ativo >0.5mL/min. Cintilografia: mais sensível para sangramento lento (0.1mL/min)."}, {t:"Doença diverticular: complicações (sangramento, diverticulite)", d:"Sangramento: divertículo de cólon D (mais comum). Diverticulite: cólon E (sigmoide). Hinchey I-II: ATB. Hinchey III-IV: cirurgia (Hartmann ou anastomose primária)."}, {t:"Classificação de hemorroidas e tratamento por grau", d:"Grau I: sangramento, sem prolapso → tratamento clínico. II: prolapso com redução espontânea → ligadura elástica. III: redução manual → ligadura ou cirurgia. IV: irredutível → hemorroidectomia."}, {t:"Fissura anal crônica: tríade (úlcera, papila hipertrófica, plicoma sentinela)", d:"Posterior em 90%. Aguda: tratamento clínico (fibras, banho de assento). Crônica (>6 sem): nitroglicerina tópica ou diltiazem; refratária: esfincterotomia lateral interna."}, {t:"Regra de Goodsall para fístulas perianais", d:"Orifício externo posterior à linha transversal: trajeto curvilíneo para a linha média posterior. Anterior: trajeto radial direto para a cripta correspondente."}] },
  // ── PEDIATRIA ──
  "itu lactente": { area: "ped", resumo: "ITU em lactente: febre sem foco é ITU até prova em contrário. Diagnóstico: EAS + urocultura (jato médio, sondagem ou punção suprapúbica — saco coletor só exclui). Tratar: cefalosporina 3ª geração se internado; cefalexina/amox-clav VO se ambulatorial. Investigação: USG renal sempre. UCM se ITU febril <2a ou USG alterada. Refluxo vesicoureteral: graus I-V.", topicos: [{t:"Coleta de urina em lactentes (punção suprapúbica > sondagem > saco)", d:"Punção suprapúbica: padrão-ouro (qualquer crescimento é positivo). Sondagem: ≥50.000 UFC/mL. Saco coletor: só serve para excluir (se negativo)."}, {t:"Critérios de internação (< 3m, toxemia, vômitos)", d:"Internar se: <3 meses, toxemia, vômitos/incapacidade de ingestão oral, desidratação, falha de tratamento ambulatorial, uropatia obstrutiva."}, {t:"Investigação por imagem (AAP 2016): USG ± UCM", d:"USG renal: obrigatória em toda 1ª ITU febril. UCM: indicada se <2 anos com ITU febril, USG alterada ou ITU recorrente. Pesquisa RVU."}, {t:"Classificação de RVU e indicação de profilaxia", d:"Graus I-II: seguimento. III: profilaxia ATB (cefalexina/SMX-TMP). IV-V: avaliar cirurgia (reimplante ureteral). Resolução espontânea é comum nos graus leves."}, {t:"Cicatriz renal: DMSA após 6 meses", d:"Cintilografia renal com DMSA: padrão-ouro para cicatriz renal. Realizar 4-6 meses após ITU. Cicatriz = nefropatia do refluxo, risco de HAS e DRC futura."}] },
  "rcp pediátrica": { area: "ped", resumo: "PCR pediátrica: causa mais comum é hipóxia (diferente do adulto=cardíaca). Compressões: 100-120/min, profundidade 1/3 do AP. Relação: 30:2 (leigo/1 socorrista) ou 15:2 (2 profissionais). FV/TV sem pulso: desfibrilar 2J/kg → 4J/kg → adrenalina 0.01mg/kg. AESP/assistolia: adrenalina a cada 3-5min. Buscar causas reversíveis: 5H 5T.", topicos: [{t:"Sequência C-A-B (PALS/AHA 2020)", d:"Compressão → Via aérea → Ventilação. Em crianças, hipóxia é a principal causa de PCR, mas a sequência C-A-B é mantida para padronização e rapidez."}, {t:"Doses pediátricas de adrenalina e amiodarona", d:"Adrenalina: 0.01mg/kg (0.1mL/kg da solução 1:10.000) IV/IO a cada 3-5min. Amiodarona: 5mg/kg IV bolus (FV/TV refratária). Alternativa: lidocaína 1mg/kg."}, {t:"Ritmos chocáveis vs não-chocáveis", d:"Chocáveis: FV e TV sem pulso → desfibrilar 2J/kg → 4J/kg → 4-10J/kg. Não-chocáveis: AESP e assistolia → adrenalina imediata + buscar causa."}, {t:"5H e 5T (causas reversíveis)", d:"5H: hipóxia, hipovolemia, H+ (acidose), hipo/hipercalemia, hipotermia. 5T: tensão (pneumotórax), tamponamento, toxinas, TEP, trombose coronariana."}, {t:"Cuidados pós-PCR: hipotermia terapêutica, evitar hiperoxia", d:"Manter normotermia ou hipotermia terapêutica (32-34°C por 24h se comatoso). Evitar hiperoxia (SpO2 94-99%). Monitorar glicemia e tratar convulsões."}] },
  "sífilis congênita": { area: "ped", resumo: "Transmissão vertical: risco maior na sífilis recente não tratada (70-100%). Prevenção: rastreio VDRL no 1º tri, 3º tri e parto. Tratamento materno adequado: penicilina benzatina, esquema completo, >30d antes do parto. RN: se mãe inadequadamente tratada → VDRL RN + hemograma + LCR + RX ossos longos. Tratar com penicilina cristalina 10d ou procaína 10d.", topicos: [{t:"Critérios de tratamento materno adequado (MS 2022)", d:"Penicilina benzatina, esquema completo para o estágio, iniciado >30 dias antes do parto, com documentação de queda do VDRL e parceiro tratado."}, {t:"Algoritmo de investigação do RN (PCDT Sífilis Congênita/MS)", d:"Mãe não/inadequadamente tratada: VDRL sangue periférico + hemograma + LCR + RX ossos longos. Tudo normal e VDRL não reagente: PB dose única. Alterado: P. cristalina 10d."}, {t:"Alterações liquóricas na neurossífilis congênita (VDRL+, cél>25, prot>150)", d:"LCR alterado se: VDRL reagente, celularidade >25 células/mm³ ou proteínas >150mg/dL. Indica neurossífilis → penicilina cristalina 50.000UI/kg IV 12/12h por 10 dias."}, {t:"Lesões ósseas: periostite, osteocondrite (sinal do duplo contorno)", d:"RX de ossos longos: periostite, osteocondrite e metafisite. Pseudoparalisia de Parrot: dor impede movimentação do membro. Presente na forma precoce (<2 anos)."}, {t:"Seguimento: VDRL mensal até negativar, VDRL LCR 6/6m se neuro", d:"VDRL sérico: mensal até 1 ano. Deve negativar ou cair 2 diluições em 3 meses. Se neurossífilis: LCR a cada 6 meses até normalizar."}] },
  "constipação/encoprese": { area: "ped", resumo: "Constipação funcional: critérios Roma IV (<2 evacuações/sem, retenção, dor). 95% funcional. Encoprese: escape fecal involuntário (>4a). Fecaloma → desimpactação (enema/PEG) → manutenção (PEG/lactulose + recondicionamento). Sinais de alarme para Hirschsprung: atraso na eliminação de mecônio >48h, distensão abdominal neonatal, não responde a laxante.", topicos: [{t:"Critérios Roma IV para constipação funcional pediátrica", d:"≥2 critérios por ≥1 mês: <2 evacuações/sem, retenção fecal, evacuação dolorosa, fezes calibrosas, massa fecal no reto, escape fecal (>4a)."}, {t:"Desimpactação: PEG via oral vs enema (NASPGHAN)", d:"PEG 3350 1-1.5g/kg/dia VO por 3-6 dias (preferível). Alternativa: enema fosfatado (>2 anos). Óleo mineral contraindicado em <1 ano e risco de aspiração."}, {t:"Doença de Hirschsprung: biópsia retal (ausência de células ganglionares)", d:"Aganglionose congênita. Suspeitar se: atraso na eliminação de mecônio >48h, constipação refratária desde neonatal. Biópsia retal por sucção é diagnóstica."}, {t:"Manometria anorretal: não-relaxamento do esfíncter interno", d:"Ausência do reflexo inibitório retoanal (RIRA) é altamente sugestiva de Hirschsprung. Exame de triagem antes da biópsia em muitos centros."}, {t:"Tratamento de manutenção: PEG 3350, orientação comportamental", d:"PEG 3350 0.4-0.8g/kg/dia por meses. Treinamento evacuatório pós-refeições (reflexo gastrocólico). Dieta rica em fibras. Desmame gradual do laxante."}] },
  "puberdade precoce": { area: "ped", resumo: "PP central (GnRH-dependente): ativação precoce do eixo HHG. Meninas <8a, meninos <9a. Causa mais comum: idiopática (meninas). Diagnóstico: LH basal ou após GnRH >0.3-0.6. RM crânio para excluir lesão (obrigatória em meninos). Tratamento: análogo de GnRH (leuprorrelina). PP periférica: independente do eixo (tumores adrenais/gonadais, HAC).", topicos: [{t:"Critérios de idade para puberdade precoce (meninas <8a, meninos <9a)", d:"Telarca antes dos 8 anos em meninas, aumento testicular (>4mL) antes dos 9 anos em meninos. Idade óssea avançada reforça o diagnóstico."}, {t:"Diferença PP central vs periférica (LH/FSH, teste do GnRH)", d:"Central: LH/FSH elevados, resposta puberal ao teste de GnRH (LH>0.3-0.6). Periférica: LH/FSH suprimidos, esteroides sexuais elevados por fonte autônoma."}, {t:"Indicação de RM de crânio (sempre em meninos)", d:"Obrigatória em todos os meninos (alta prevalência de lesão: hamartoma, glioma). Em meninas: indicar se <6 anos ou sinais neurológicos."}, {t:"Tratamento com análogo de GnRH (ESPE/Lawson Wilkins)", d:"Leuprorrelina 3.75mg IM mensal ou 11.25mg trimestral. Suprime eixo HHG, freia progressão puberal e melhora estatura final. Reversível após suspensão."}, {t:"HAC como causa de PP periférica (21-hidroxilase)", d:"Deficiência de 21-OH → excesso de andrógenos adrenais → pubarca precoce, acne, avanço de IO. Forma não clássica pode se apresentar como PP periférica."}] },
  "hiperplasia adrenal congênita": { area: "ped", resumo: "Deficiência de 21-hidroxilase (>90%). Forma clássica perdedora de sal: crise adrenal neonatal (vômitos, desidratação, hipoNa+, hiperK+). Forma virilizante simples: genitália ambígua (meninas), pubarca precoce. Diagnóstico: 17-OH-progesterona elevada (teste do pezinho). Tratamento: hidrocortisona + fludrocortisona (se perdedora de sal).", topicos: [{t:"Triagem neonatal: 17-OHP no teste do pezinho (MS/SBP)", d:"17-OHP elevada no teste do pezinho (3º-5º dia). Prematuros e baixo peso: valores de corte ajustados (falso-positivo mais frequente)."}, {t:"Forma perdedora de sal vs virilizante simples", d:"Perdedora de sal (75%): crise adrenal na 2ª-3ª semana (vômitos, desidratação, hipoNa, hiperK). Virilizante simples: genitália ambígua na menina, sem perda de sal."}, {t:"Genitália ambígua: classificação de Prader", d:"Prader I: clitoromegalia. II-III: fusão labial progressiva. IV: uretra fálica. V: genitália masculina completa. HAC 46,XX é a causa mais comum de genitália ambígua."}, {t:"Crise adrenal: hidrocortisona EV em dose de estresse", d:"Hidrocortisona 50-100mg/m² IV em bolus, depois 50-100mg/m²/dia. SF 0.9% 20mL/kg para expansão. Corrigir hipoglicemia. Monitorar eletrólitos."}, {t:"Monitoramento: 17-OHP, androstenediona, idade óssea", d:"17-OHP e androstenediona para ajuste de dose de hidrocortisona. Idade óssea anual (avanço indica subdose). Renina e eletrólitos para ajuste de fludrocortisona."}] },
  "doenças exantemáticas": { area: "ped", resumo: "Sarampo: pródromos catarrais + Koplik + exantema craniocaudal. Rubéola: exantema + linfadenopatia retroauricular. Eritema infeccioso (parvovírus B19): face esbofeteada. Exantema súbito (HHV-6): febre alta 3d → exantema ao ceder febre. Varicela: vesículas em diferentes estágios + polimorfismo regional. Escarlatina: faringite estreptocócica + exantema micropapular + Pastia.", topicos: [{t:"Diagnóstico diferencial dos exantemas na infância", d:"Sarampo: craniocaudal, Koplik. Rubéola: retroauricular. Eritema infeccioso: face esbofeteada. Exantema súbito: febre→exantema. Escarlatina: micropapular, Pastia. Varicela: polimorfismo."}, {t:"Sarampo: complicações (pneumonia, encefalite, PEES)", d:"Pneumonia: principal causa de óbito. Encefalite aguda: 1-2/1000 casos. PEES (panencefalite esclerosante subaguda): anos após, degeneração neurológica fatal. Vitamina A reduz mortalidade."}, {t:"Síndrome da rubéola congênita (tríade de Gregg)", d:"Surdez neurossensorial + cardiopatia (PCA, estenose pulmonar) + catarata. Maior risco se infecção no 1º trimestre. Prevenção: vacinação pré-concepcional."}, {t:"Varicela: complicações e indicação de aciclovir", d:"Infecção bacteriana secundária (mais comum), pneumonia, encefalite cerebelar. Aciclovir VO: >12a, doença pulmonar crônica, uso de corticoide, 2º caso domiciliar. IV: imunodeprimidos."}, {t:"Calendário vacinal: tríplice viral e varicela (PNI/MS)", d:"Tríplice viral (SCR): 12m e 15m (tetra viral = SCR + varicela). Varicela isolada: dose única entre 4-6 anos se não recebeu tetra viral."}] },
  // ── GINECOLOGIA E OBSTETRÍCIA ──
  "rciu/dg": { area: "go", resumo: "RCIU: peso estimado <p10. Causas: insuficiência placentária (tipo II assimétrico, mais comum), genético (tipo I simétrico). Doppler de a. umbilical: IP elevado → diástole zero → diástole reversa (urgência). DG: TOTG 75g 24-28 sem (GJ≥92, 1h≥180, 2h≥153). Tratar: dieta + atividade física → insulina se metas não atingidas (GJ<95, 1h pós<140).", topicos: [{t:"Classificação RCIU simétrico vs assimétrico", d:"Simétrico (tipo I): insulto precoce (genético, infecção), todos os parâmetros reduzidos proporcionalmente. Assimétrico (tipo II): insuficiência placentária tardia, CC preservada, CA reduzida."}, {t:"Doppler de artéria umbilical e cerebral média (centralização)", d:"Umbilical: IP elevado = resistência placentária aumentada. Centralização: redistribuição de fluxo para cérebro (ACM com IP baixo). ICP<1 = centralização."}, {t:"Critérios diagnósticos de DMG (IADPSG/FIGO/MS)", d:"TOTG 75g entre 24-28 semanas. Positivo se qualquer valor: GJ≥92, 1h≥180, 2h≥153mg/dL. GJ≥126 ou glicemia aleatória≥200 = DM prévio (overt diabetes)."}, {t:"Metas glicêmicas na gestação (MS/SBD)", d:"GJ e pré-prandial <95mg/dL. 1h pós-prandial <140mg/dL. 2h pós-prandial <120mg/dL. HbA1c<6% (DM prévio). Hipoglicemia deve ser evitada."}, {t:"Momento do parto no RCIU com Doppler alterado", d:"IP umbilical elevado isolado: parto 37-38sem. Centralização: parto 34-37sem com corticoide. Diástole zero/reversa: corticoide + parto 30-34sem. DV alterado: parto imediato se >26sem."}] },
  "rciu/doppler": { area: "go", resumo: "Avaliação fetal no RCIU: Doppler de a. umbilical (rastreio), ACM (centralização = brain sparing), ducto venoso (onda A ausente/reversa = descompensação). Sequência: IP umbilical↑ → centralização (relação cérebro-placentária<1) → ducto venoso alterado → óbito. Conduta: leve (acompanhar), moderado (corticoide + parto ~34sem), grave (parto se DV alterado ou >26sem).", topicos: [{t:"Índice cérebro-placentário (ICP) e centralização fetal", d:"ICP = IP ACM / IP umbilical. ICP<1 indica centralização (brain sparing): vasodilatação cerebral compensatória. Sinal de hipóxia fetal crônica."}, {t:"Doppler do ducto venoso: onda A e prognóstico", d:"Onda A do DV reflete função cardíaca fetal. Onda A ausente: acidemia fetal. Onda A reversa: risco iminente de óbito, indicação de parto se viável."}, {t:"Corticoide antenatal: betametasona 12mg IM 2 doses (24-34sem)", d:"Betametasona 12mg IM, 2 doses com intervalo de 24h (ou dexametasona 6mg IM 12/12h, 4 doses). Indicado entre 24-34sem se risco de parto prematuro em 7 dias."}, {t:"Indicações de parto prematuro no RCIU", d:"Doppler de DV alterado (onda A ausente/reversa): parto independente da IG se >26sem. Centralização + oligoâmnio: parto ~34sem. Sempre ponderar risco prematuridade vs hipóxia."}, {t:"Perfil biofísico fetal: pontuação e conduta", d:"5 parâmetros (2 pontos cada): MRF, movimentos corporais, tônus, LA, CTG reativa. 8-10: normal. 6: repetir em 24h. ≤4: considerar parto. LA é o mais importante cronicamente."}] },
  "acretismo placentário": { area: "go", resumo: "Placenta com invasão anormal do miométrio. Tipos: acreta (superficial), increta (miométrio), percreta (serosa/órgãos). Fator de risco principal: placenta prévia + cesárea anterior. Diagnóstico: USG (perda do espaço claro retroplacentário, lagos placentários) ± RM. Conduta: cesárea programada 34-36 sem com equipe multidisciplinar. Histerectomia na maioria dos casos de percreta.", topicos: [{t:"Classificação: acreta vs increta vs percreta", d:"Acreta: vilosidades aderem ao miométrio superficial. Increta: invadem o miométrio. Percreta: atravessam a serosa, podendo atingir bexiga. Gravidade crescente."}, {t:"Fatores de risco (nº de cesáreas prévias + placenta prévia)", d:"Risco aumenta exponencialmente: placenta prévia + 1 cesárea = 3%; + 2 cesáreas = 11%; + 3 = 40%; + 4 = 61%. Placenta prévia é o principal fator associado."}, {t:"Achados ultrassonográficos sugestivos (FIGO)", d:"Perda do espaço claro retroplacentário, lagos vasculares placentários, afinamento miometrial, vascularização aumentada na interface. RM complementa em casos duvidosos."}, {t:"Planejamento cirúrgico: reserva de hemoderivados, equipe", d:"Cesárea programada 34-36sem em centro terciário. Reservar ≥6CH. Equipe: obstetra, urologista, cirurgião vascular, anestesista, banco de sangue preparado."}, {t:"Manejo conservador (quando preservar útero): triple-P procedure", d:"Deixar placenta in situ + metotrexato: apenas em acreta focal com desejo reprodutivo. Alto risco de infecção e hemorragia tardia. Histerectomia é o padrão em percreta."}] },
  "dpp": { area: "go", resumo: "Descolamento prematuro de placenta: sangramento vaginal escuro + dor + hipertonia uterina + sofrimento fetal. Fator de risco: HAS (principal), trauma, cocaína, polidrâmnio. Classificação: grau 0 (achado retro), I (sangramento leve), II (sofrimento fetal), III (óbito fetal ± CIVD). Conduta: grau I = amniotomia + parto vaginal se condições. Grau II-III = cesárea de urgência. CIVD: repor fibrinogênio.", topicos: [{t:"Quadro clínico clássico (sangramento + dor + hipertonia)", d:"Sangramento vaginal escuro (pode ser oculto em 20%), dor abdominal súbita, hipertonia uterina (útero lenhoso) e sofrimento fetal. HAS é o principal fator de risco."}, {t:"Classificação de Sher (graus 0-III)", d:"0: assintomático, achado retroplacentário. I: sangramento leve, sem sofrimento fetal. II: sangramento moderado + sofrimento fetal + feto vivo. III: óbito fetal ± CIVD (IIIa sem, IIIb com CIVD)."}, {t:"Conduta obstétrica por gravidade", d:"Grau I: amniotomia + indução se condições favoráveis. Grau II: cesárea de urgência (feto vivo em sofrimento). Grau III: estabilizar mãe + parto via mais rápida."}, {t:"CIVD: quando suspeitar e como repor (crioprecipitado)", d:"Suspeitar se sangramento difuso + fibrinogênio<200. Repor crioprecipitado (1U/10kg eleva fibrinogênio ~50mg/dL). Manter fibrinogênio>200, plaquetas>50.000."}, {t:"Útero de Couvelaire e indicação de histerectomia", d:"Infiltração hemorrágica do miométrio (útero arroxeado). NÃO é indicação absoluta de histerectomia. Indicar apenas se atonia refratária após todas as medidas (massagem, uterotônicos, B-Lynch)."}] },
  "rpmo pré-termo": { area: "go", resumo: "Rotura prematura de membranas ovulares antes de 37 sem. Diagnóstico: anamnese + exame especular (líquido no fundo de saco) + testes (cristalização, pH vaginal >6.5, IGFBP-1/PAMG-1). NÃO fazer toque! Conduta <34sem: internação + corticoide + ATB (ampicilina+azitromicina) + tocólise de curso. ≥34sem: resolução. Complicações: corioamnionite, prematuridade, prolapso de cordão.", topicos: [{t:"Diagnóstico clínico e laboratorial (não fazer toque digital)", d:"Exame especular: líquido amniótico no fundo de saco ou saindo pelo OE. Testes: cristalização em folha de samambaia, pH>6.5 (azul no papel de nitrazina). IGFBP-1/PAMG-1 se dúvida."}, {t:"Corticoide antenatal: indicação 24-34 semanas", d:"Betametasona 12mg IM, 2 doses (24h intervalo). Maturação pulmonar fetal. Efeito máximo 48h após início, dura 7 dias. Resgate: considerar se >14 dias e <34sem."}, {t:"Antibioticoterapia na RPMO (esquema ACOG/MS)", d:"Ampicilina 2g IV 6/6h + azitromicina 1g VO dose única por 48h → amoxicilina 500mg VO 8/8h por 5 dias. Prolonga latência e reduz corioamnionite."}, {t:"Sinais de corioamnionite (febre + taquicardia + útero doloroso)", d:"Febre materna ≥38°C + taquicardia materna/fetal + útero doloroso + LA fétido/purulento. Indicação absoluta de parto independente da IG."}, {t:"Conduta por idade gestacional (limiar de viabilidade a 34 sem)", d:"<24sem: individualizar (limiar de viabilidade). 24-34sem: conduta expectante com corticoide + ATB + vigilância. ≥34sem: resolução da gestação (indução ou cesárea)."}] },
  "mamografia bi-rads": { area: "go", resumo: "BI-RADS: 0=incompleto, 1=normal, 2=benigno, 3=provavelmente benigno (<2% malignidade, controle 6m), 4=suspeito (biopsiar), 5=altamente suspeito (biopsiar), 6=malignidade confirmada. Rastreamento MS: mamografia bienal 50-69a. FEBRASGO/SBM: anual a partir de 40a. Fatores de risco: história familiar 1ºgrau, mutação BRCA, radioterapia torácica.", topicos: [{t:"Classificação BI-RADS e conduta por categoria (ACR)", d:"0: complementar. 1: normal (anual). 2: benigno (anual). 3: provavelmente benigno (<2% Ca, controle 6m). 4: suspeito (biópsia). 5: altamente suspeito (biópsia). 6: Ca confirmado."}, {t:"Rastreamento: MS (50-69 bienal) vs FEBRASGO (40+ anual)", d:"MS/INCA: mamografia bienal 50-69a. FEBRASGO/SBM/CBR: anual a partir de 40a. Alto risco: iniciar 10 anos antes do caso índice, nunca antes de 25a."}, {t:"Indicação de RM mamária (alto risco, BRCA)", d:"RM anual + mamografia para risco ≥20% vitalício: BRCA1/2, Li-Fraumeni, RT torácica entre 10-30a. RM tem maior sensibilidade mas menor especificidade."}, {t:"Achados mamográficos suspeitos: microcalcificações pleomórficas, nódulo espiculado", d:"Nódulo espiculado, microcalcificações pleomórficas agrupadas, distorção arquitetural, assimetria focal com calcificações. BI-RADS 4 ou 5."}, {t:"Core biopsy vs PAAF vs biópsia excisional", d:"Core biopsy (agulha grossa): padrão para nódulos sólidos (histológico). PAAF: cistos e linfonodos. Mamotomia: microcalcificações. Biópsia excisional: quando percutânea inconclusiva."}] },
  "vaginose bacteriana": { area: "go", resumo: "Desequilíbrio da flora vaginal: ↓lactobacilos, ↑Gardnerella + anaeróbios. Corrimento acinzentado, fétido (peixe), pH>4.5. Critérios de Amsel (3/4): corrimento homogêneo, pH>4.5, teste das aminas+, clue cells. Nugent ≥7 (padrão-ouro). Tratamento: metronidazol 500mg VO 12/12h 7d ou gel vaginal 5d. Na gestação: tratar todas (risco de RPMO, prematuridade).", topicos: [{t:"Critérios de Amsel (3 de 4 para diagnóstico)", d:"1) Corrimento homogêneo acinzentado, 2) pH vaginal >4.5, 3) Teste das aminas positivo (KOH = odor de peixe), 4) Clue cells na microscopia."}, {t:"Escore de Nugent na bacterioscopia (padrão-ouro)", d:"Escore 0-3: normal. 4-6: intermediário. 7-10: vaginose bacteriana. Avalia proporção de lactobacilos vs Gardnerella/Mobiluncus no Gram."}, {t:"Tratamento: metronidazol vs clindamicina (MS/CDC)", d:"1ª linha: metronidazol 500mg VO 12/12h por 7d ou gel vaginal 0.75% 1x/dia por 5d. Alternativa: clindamicina creme vaginal 2% por 7 noites."}, {t:"VB na gestação: associação com prematuridade e RPMO", d:"VB aumenta risco de RPMO, parto prematuro e endometrite pós-parto. Tratar TODAS as gestantes sintomáticas. Metronidazol VO é seguro após 1º trimestre."}, {t:"Diferencial: VB vs candidíase vs tricomoníase", d:"VB: cinza, fétido, pH>4.5, clue cells. Candidíase: branco grumoso, prurido, pH<4.5, pseudo-hifas. Tricomoníase: amarelo-esverdeado, bolhoso, pH>5, protozoário móvel."}] },
  "fórceps": { area: "go", resumo: "Indicações: período expulsivo prolongado, sofrimento fetal agudo, exaustão materna. Condições: dilatação total, membranas rotas, cabeça insinuada (De Lee ≥+2), variedade de posição conhecida, bexiga vazia. Tipos: Simpson (rotação), Kielland (rotações difíceis), Piper (cabeça derradeira no pélvico). Classificação: de alívio (≥+3), baixo (+2/+3), médio (acima de +2).", topicos: [{t:"Condições de aplicabilidade (ACOG)", d:"Dilatação total, membranas rotas, cabeça insinuada (≥plano +2 De Lee), apresentação cefálica, variedade conhecida, bexiga vazia, analgesia adequada."}, {t:"Classificação: alívio vs baixo vs médio (ACOG)", d:"Alívio: escalpo visível, ≥+3. Baixo: +2/+3, rotação ≤45°. Médio: acima de +2 mas insinuado. Alto: não insinuado (CONTRAINDICADO, abandonado)."}, {t:"Tipos de fórceps e indicação de cada um", d:"Simpson: mais versátil, rotações ≤45°. Kielland: rotações amplas (transversa→OP), ramos cruzados. Piper: cabeça derradeira no pélvico. Barton: variedade transversa alta."}, {t:"Complicações maternas (laceração) e fetais (cefalohematoma, paralisia facial)", d:"Maternas: laceração cervical, vaginal, perineal (3º-4º grau). Fetais: cefalohematoma, paralisia facial (VII par), lesão de plexo braquial, fratura de crânio (raro)."}, {t:"Vácuo-extrator como alternativa e suas contraindicações", d:"Vantagens: menor trauma materno, não requer conhecer variedade. Contraindicações: <34sem, face, pélvico. Máximo 3 trações ou 20min. Risco de cefalohematoma e hemorragia subgaleal."}] },
  "sangramento pós-menopausa": { area: "go", resumo: "Sempre investigar! Causa mais comum: atrofia endometrial. Mais temida: câncer de endométrio. USG TV: eco endometrial >4-5mm → biópsia (histeroscopia com biópsia é padrão-ouro). Fatores de risco para Ca endométrio: obesidade, nuliparidade, SOP, TH estrogênica isolada, tamoxifeno. Câncer de endométrio: tipo I (endometrioide, mais comum, bom prognóstico) vs tipo II (seroso/células claras).", topicos: [{t:"Espessura endometrial de corte na pós-menopausa (>4-5mm)", d:"Eco endometrial ≤4-5mm na USG TV tem VPN >99% para Ca endometrial. Acima desse corte: biopsiar. Se em uso de tamoxifeno: maior espessura não necessariamente é patológica."}, {t:"Investigação: USG TV → histeroscopia + biópsia", d:"USG TV é o 1º exame. Eco >4-5mm ou sangramento recorrente: histeroscopia com biópsia dirigida (padrão-ouro). Biópsia aspirativa (Pipelle) é alternativa ambulatorial."}, {t:"Fatores de risco para Ca endométrio (estímulo estrogênico)", d:"Obesidade (aromatase periférica), nuliparidade, menarca precoce, menopausa tardia, SOP, TH estrogênica isolada, tamoxifeno, síndrome de Lynch."}, {t:"Estadiamento FIGO do Ca de endométrio", d:"IA: endométrio ou <50% miométrio. IB: ≥50% miométrio. II: estroma cervical. III: extensão local/linfonodal. IV: bexiga/reto ou metástase a distância. Cirúrgico."}, {t:"Hiperplasia endometrial: simples vs complexa vs com atipia", d:"Sem atipia: risco de Ca 1-3%, tratar com progestágeno. Com atipia: risco de Ca 30-40%, histerectomia é o tratamento (ou progestágeno se desejo reprodutivo)."}] },
  "células glandulares atípicas": { area: "go", resumo: "AGC no citopatológico cervical: risco significativo de lesão de alto grau ou adenocarcinoma (até 30-50%). Conduta: colposcopia + biópsia endocervical + biópsia endometrial (se >35a ou sangramento). Se AGC favorecendo neoplasia: excisão tipo 3 (conização). Diferente do ASC-US (baixo risco). AGC sempre requer investigação completa.", topicos: [{t:"Conduta diante de AGC (Diretrizes MS/INCA 2016)", d:"Colposcopia + biópsia endocervical obrigatórios. Se >35 anos ou sangramento anormal: adicionar avaliação endometrial. AGC é achado de alto risco, diferente de ASC-US."}, {t:"Diferencial: AGC de origem endocervical vs endometrial", d:"Endocervical: adenocarcinoma in situ ou invasor do colo. Endometrial: hiperplasia com atipia ou Ca de endométrio. A origem determina a investigação complementar."}, {t:"Indicação de conização e curetagem endocervical", d:"Conização (excisão tipo 3): AGC favorecendo neoplasia ou AIS. Curetagem endocervical: complementar à colposcopia quando ZT não visível ou AGC-SOE."}, {t:"Investigação endometrial em mulheres >35 anos", d:"USG TV + histeroscopia com biópsia ou biópsia aspirativa (Pipelle). Obrigatória se >35 anos com AGC, sangramento pós-menopausa ou irregularidade menstrual."}, {t:"Seguimento após resultado AGC tratado", d:"Citologia e colposcopia semestral por 2 anos. Se AIS na conização com margens livres: seguimento rigoroso (recidiva ~5%). Margens comprometidas: reconização ou histerectomia."}] },
  "insuf. ovariana prematura": { area: "go", resumo: "Falência ovariana antes dos 40 anos. FSH >25-40 UI/L (2 dosagens com intervalo ≥4 sem) + amenorreia/oligomenorreia. Causas: idiopática (maioria), autoimune (tireoidite, Addison), genética (Turner, Frágil X), iatrogênica (QT/RT). Consequências: infertilidade, osteoporose, risco CV. Tratamento: TH até idade da menopausa natural (~50a).", topicos: [{t:"Critérios diagnósticos (FSH elevado + amenorreia <40a)", d:"FSH >25-40 UI/L em 2 dosagens com intervalo ≥4 semanas + amenorreia ou oligomenorreia em mulher <40 anos. Estradiol baixo confirma hipoestrogenismo."}, {t:"Investigação: cariótipo, FMR1, autoanticorpos, TSH", d:"Cariótipo: excluir Turner (45,X) e mosaicismos. FMR1: pré-mutação do X-frágil (causa comum). Anti-21-hidroxilase, anti-adrenal: causa autoimune. TSH: associação com tireoidite."}, {t:"Síndrome de Turner: cariótipo 45,X", d:"Baixa estatura, pescoço alado, cúbito valgo, coarctação de aorta, rim em ferradura. Disgenesia gonadal → amenorreia primária + FSH elevado. Tratar com GH + TH."}, {t:"TH: estrogênio + progesterona até 50 anos (EMAS/IMS)", d:"TH é recomendada até a idade da menopausa natural (~50-51a) para proteção óssea, cardiovascular e de sintomas. Estrogênio + progesterona se útero presente."}, {t:"Fertilidade: doação de óócitos", d:"Ovulação espontânea pode ocorrer esporadicamente (5-10%). Para gestação programada: doação de óócitos + FIV é a opção mais eficaz. Gravidez espontânea é rara."}] },
  // ── PREVENTIVA / SAÚDE COLETIVA ──
  "bradford hill": { area: "preventiva", resumo: "Critérios de causalidade de Bradford Hill (1965): força da associação, consistência, especificidade, temporalidade (único obrigatório), gradiente biológico (dose-resposta), plausibilidade biológica, coerência, evidência experimental, analogia. Usados para avaliar se associação epidemiológica é causal. Temporalidade é o único critério indispensável.", topicos: [{t:"Os 9 critérios de Bradford Hill", d:"Força, consistência, especificidade, temporalidade, gradiente biológico, plausibilidade, coerência, evidência experimental e analogia. São critérios, não regras absolutas."}, {t:"Temporalidade como único critério obrigatório", d:"A causa DEVE preceder o efeito. Único critério considerado indispensável entre os 9. Estudos transversais não permitem avaliar temporalidade."}, {t:"Força da associação: RR e OR elevados", d:"Quanto maior o RR ou OR, mais provável que a associação seja causal. RR>2 geralmente considerado forte. Mas associação fraca não exclui causalidade."}, {t:"Gradiente biológico (dose-resposta)", d:"Maior exposição = maior risco. Exemplo clássico: número de cigarros/dia e risco de Ca de pulmão. Reforça a hipótese causal, mas não é obrigatório."}, {t:"Aplicação em questões de prova: diferenciar associação de causalidade", d:"Associação estatística (p<0.05) NÃO implica causalidade. Aplicar critérios de Hill para avaliar. Vieses (seleção, aferição) e confundimento podem gerar associação espúria."}] },
  "freq. epidemiológica": { area: "preventiva", resumo: "Incidência: casos NOVOS / população em risco no período. Prevalência: casos EXISTENTES / população total no momento. Relação: prevalência ≈ incidência × duração. Taxa de ataque: incidência em surto. Mortalidade: óbitos / população. Letalidade: óbitos / doentes. Prevalência aumenta com: ↑incidência, ↑duração. Prevalência diminui com: cura ou óbito rápido.", topicos: [{t:"Incidência acumulada vs taxa de incidência (pessoa-tempo)", d:"Incidência acumulada: casos novos/população em risco no início (proporção). Taxa de incidência: casos novos/pessoa-tempo de observação (taxa). Pessoa-tempo considera tempo variável de seguimento."}, {t:"Prevalência pontual vs de período", d:"Pontual: casos existentes em um momento. Período: casos existentes em intervalo de tempo (inclui novos + preexistentes). Prevalência é proporção, não taxa."}, {t:"Relação entre prevalência, incidência e duração", d:"Prevalência ≈ incidência × duração média da doença (quando prevalência <10%). Doença crônica incurável: prevalência sobe. Doença letal rápida: prevalência baixa."}, {t:"Letalidade vs mortalidade (denominadores diferentes)", d:"Letalidade = óbitos pela doença / doentes (gravidade da doença). Mortalidade = óbitos / população total (impacto populacional). Ebola: alta letalidade, baixa mortalidade."}, {t:"Taxa de ataque em surtos/epidemias", d:"Incidência acumulada durante surto: doentes / expostos × 100. Taxa de ataque secundária: casos entre contactantes / total de contactantes. Usada para avaliar transmissibilidade."}] },
  "tx mortalidade bruta": { area: "preventiva", resumo: "Taxa de mortalidade geral (bruta): total de óbitos / população total × 1000. Não ajusta por idade → enviesada pela estrutura etária. Comparação entre populações requer padronização (direta ou indireta). Taxa específica por idade: óbitos na faixa / população na faixa. Mortalidade infantil: <1 ano / nascidos vivos × 1000. Neonatal: <28d. Pós-neonatal: 28d-1a.", topicos: [{t:"Mortalidade bruta vs específica vs padronizada", d:"Bruta: todos os óbitos/população (não permite comparação entre populações com estrutura etária diferente). Específica: por faixa etária. Padronizada: ajustada para comparação."}, {t:"Método direto vs indireto de padronização", d:"Direto: aplica taxas específicas locais à população padrão (precisa de taxas específicas). Indireto: aplica taxas padrão à estrutura local, gera SMR (populações pequenas)."}, {t:"Mortalidade infantil: neonatal precoce (<7d), neonatal tardia (7-27d), pós-neonatal (28d-1a)", d:"TMI = óbitos <1a / NV × 1000. Neonatal precoce: asfixia, prematuridade. Neonatal tardia: infecções. Pós-neonatal: causas evitáveis (diarreia, pneumonia, desnutrição)."}, {t:"Razão de mortalidade materna (RMM): óbitos maternos / NV × 100.000", d:"Óbitos por causas obstétricas (até 42d pós-parto) / NV × 100.000. Brasil ~60/100.000. Causas: hipertensão, hemorragia, infecção. ODS: <30/100.000 até 2030."}, {t:"Transição epidemiológica no Brasil", d:"Mudança de doenças infecciosas para crônico-degenerativas como principais causas de morbimortalidade. Brasil: transição incompleta (polarização = coexistência de ambos os padrões)."}] },
  "tx mortalidade padronizada": { area: "preventiva", resumo: "Padronização: elimina efeito confundidor da idade. Método direto: aplica taxas específicas por idade da pop. estudada a uma pop. padrão → comparável entre localidades. Método indireto: aplica taxas da pop. padrão à estrutura etária da pop. estudada → gera SMR (razão de mortalidade padronizada). SMR >1: mortalidade maior que o padrão.", topicos: [{t:"Padronização direta: quando temos taxas específicas por faixa etária", d:"Aplica as taxas específicas por idade da população em estudo a uma população padrão de referência. Requer conhecer as taxas específicas de cada faixa."}, {t:"Padronização indireta: quando taxas específicas são instáveis (pop. pequena)", d:"Aplica as taxas da população padrão à estrutura etária local. Usa-se quando a população é pequena e as taxas específicas são instáveis. Gera o SMR."}, {t:"SMR (Standardized Mortality Ratio): observados/esperados", d:"SMR = óbitos observados / óbitos esperados. SMR>1: mortalidade maior que a referência. SMR<1: menor. É o resultado da padronização indireta."}, {t:"Escolha da população padrão", d:"Pode ser uma das populações comparadas, a soma delas, ou uma população de referência (ex: OMS, Brasil). A escolha influencia o resultado, mas a direção da comparação geralmente se mantém."}, {t:"Quando usar cada método em questões de prova", d:"Direto: quando dispõe de taxas específicas e populações grandes. Indireto: quando taxas específicas não são confiáveis (pop. pequena). Prova cobra: identificar o método pelo procedimento descrito."}] },
  "eixos saúde trabalhador": { area: "preventiva", resumo: "Política Nacional de Saúde do Trabalhador (PNST/MS 2012): atenção integral, vigilância em saúde do trabalhador (VISAT), promoção da saúde. RENAST: Rede Nacional de Atenção Integral à Saúde do Trabalhador. CEREST: referência regional. Notificação compulsória: acidente grave, intoxicações, doenças relacionadas ao trabalho (SINAN). Nexo técnico epidemiológico (NTEP): presunção de nexo causal.", topicos: [{t:"RENAST e papel dos CERESTs", d:"RENAST: rede de atenção à saúde do trabalhador no SUS. CERESTs: centros de referência estaduais/regionais para diagnóstico, tratamento e vigilância de doenças ocupacionais."}, {t:"Notificação compulsória de agravos ocupacionais (SINAN-NET)", d:"Acidentes de trabalho graves, fatais e em menores. Intoxicações exógenas, pneumoconioses, dermatoses, LER/DORT, perda auditiva. Notificação no SINAN, independente do vínculo."}, {t:"Nexo técnico epidemiológico (NTEP) previdenciário", d:"Presunção de nexo causal entre doença e atividade profissional baseada em dados epidemiológicos. Inverte o ônus da prova: empresa deve provar que NÃO há relação."}, {t:"Lista de doenças relacionadas ao trabalho (MS)", d:"Portaria MS 1339/1999 (atualizada): lista de doenças por agente/exposição. Inclui LER/DORT, pneumoconioses (silicose, asbestose), intoxicações, neoplasias ocupacionais."}, {t:"Vigilância em Saúde do Trabalhador (VISAT): conceito e ações", d:"Conjunto de ações de vigilância epidemiológica + sanitária + ambiental voltadas à saúde do trabalhador. Inclui inspeção de ambientes, análise de processos e notificação."}] },
  "regionalização sus": { area: "preventiva", resumo: "Princípio organizativo do SUS: hierarquização em níveis (atenção primária, secundária, terciária) organizada por regiões de saúde. Região de saúde: espaço geográfico contínuo com município-sede e rede de serviços. Instrumentos: PDR (Plano Diretor de Regionalização), PPI (Programação Pactuada Integrada), COAP/RAPS. Decreto 7508/2011 regulamenta.", topicos: [{t:"Decreto 7508/2011: regiões de saúde e RENAME/RENASES", d:"Regulamenta a Lei 8080. Define região de saúde, RENAME (medicamentos essenciais), RENASES (ações e serviços). Obriga contrato organizativo (COAP) entre entes federados."}, {t:"PDR e PPI como instrumentos de planejamento", d:"PDR: define regiões e fluxos de referência. PPI: programa a oferta de serviços e define tetos financeiros entre municípios. Ambos são instrumentos de gestão compartilhada."}, {t:"Redes de Atenção à Saúde (RAS): Rede Cegonha, Rede de Urgência", d:"RAS: arranjos organizativos de ações e serviços integrados. Rede Cegonha: materno-infantil. Rede de Urgência/Emergência: SAMU, UPA, portas hospitalares. APS é a coordenadora."}, {t:"CIR (Comissão Intergestores Regional)", d:"Espaço de negociação entre gestores municipais e estadual na região de saúde. Instância de governança regional. Equivalente regional da CIB (estadual) e CIT (federal)."}, {t:"Diferença entre descentralização e regionalização", d:"Descentralização: transferência de responsabilidades da União para estados/municípios. Regionalização: organização territorial dos serviços em redes regionais. Complementares, não sinônimos."}] },
  "prevenção quaternária": { area: "preventiva", resumo: "Prevenir o excesso de medicalização e iatrogenia. Proteger o paciente de intervenções desnecessárias. Conceito de Marc Jamoulle (WONCA). Evitar sobrediagnóstico (overdiagnosis) e sobretratamento (overtreatment). Exemplos: não rastrear Ca próstata com PSA de rotina em >70a; evitar exames de imagem para lombalgia aguda sem sinais de alarme.", topicos: [{t:"Definição e diferença das 4 prevenções (primária a quaternária)", d:"Primária: evitar doença (vacina). Secundária: detecção precoce (rastreamento). Terciária: reabilitação e redução de sequelas. Quaternária: proteger de intervenções desnecessárias."}, {t:"Sobrediagnóstico (overdiagnosis): conceito e exemplos", d:"Diagnóstico de condição que nunca causaria sintomas ou morte. Exemplos: Ca de tireoide incidental, Ca de próstata indolente em idoso, incidentaloma adrenal benigno."}, {t:"Choosing Wisely / Menos é Mais Saúde", d:"Movimento internacional para reduzir exames e tratamentos desnecessários. Listas de recomendações 'não fazer' por especialidade. No Brasil: projeto 'Menos é Mais Saúde' (SBMFC)."}, {t:"NNT e NNH na avaliação de intervenções", d:"NNT (número necessário para tratar): quantos pacientes tratar para 1 benefício. NNH: quantos para 1 dano. Ideal: NNT baixo e NNH alto. NNT = 1/RAR."}, {t:"Prevenção quaternária na APS (WONCA/SBMFC)", d:"Papel central do médico de família: filtrar demandas, evitar cascata diagnóstica, não medicalizar sofrimento normal. Marc Jamoulle (1986): conceito dentro da classificação de prevenções."}] },
};
